// ─── TF-IDF Implementation ──────────────────────────────────────────────────
let tfidfCache = null;

function tokenize(text) {
  return text.toLowerCase()
    .replace(/[^a-z0-9\s]/g, ' ')
    .split(/\s+/)
    .filter(t => t.length > 2 && t.length < 50);
}

function buildTFIDF() {
  const docs = REGULATORY_CORPUS.map(doc => ({
    ...doc,
    tokens: tokenize(doc.text),
  }));

  // Document frequency
  const df = {};
  for (const doc of docs) {
    const unique = new Set(doc.tokens);
    for (const token of unique) {
      df[token] = (df[token] || 0) + 1;
    }
  }

  const N = docs.length;

  // TF-IDF vectors
  const vectors = docs.map(doc => {
    const tf = {};
    for (const token of doc.tokens) {
      tf[token] = (tf[token] || 0) + 1;
    }
    const vec = {};
    for (const [token, count] of Object.entries(tf)) {
      const idf = Math.log((N + 1) / (df[token] + 1)) + 1;
      vec[token] = (count / doc.tokens.length) * idf;
    }
    return vec;
  });

  tfidfCache = { docs, vectors };
  return tfidfCache;
}

function cosineSimilarity(vecA, vecB) {
  let dotProduct = 0;
  let normA = 0;
  let normB = 0;

  const allTokens = new Set([...Object.keys(vecA), ...Object.keys(vecB)]);
  for (const token of allTokens) {
    const a = vecA[token] || 0;
    const b = vecB[token] || 0;
    dotProduct += a * b;
    normA += a * a;
    normB += b * b;
  }

  const magnitude = Math.sqrt(normA) * Math.sqrt(normB);
  return magnitude === 0 ? 0 : dotProduct / magnitude;
}

// ─── Search ─────────────────────────────────────────────────────────────────
export function searchRegulations(query, { category = null, limit = 10 } = {}) {
  const cache = tfidfCache || buildTFIDF();

  const queryTokens = tokenize(query);
  if (queryTokens.length === 0) return [];

  // Build query vector
  const queryVec = {};
  const df = {};
  for (const doc of cache.docs) {
    const unique = new Set(doc.tokens);
    for (const token of unique) {
      df[token] = (df[token] || 0) + 1;
    }
  }
  const N = cache.docs.length;
  for (const token of queryTokens) {
    const idf = Math.log((N + 1) / ((df[token] || 0) + 1)) + 1;
    queryVec[token] = (1 / queryTokens.length) * idf;
  }

  // Score documents
  const scored = cache.docs.map((doc, i) => {
    const sim = cosineSimilarity(queryVec, cache.vectors[i]);
    return { doc, score: sim };
  });

  // Filter by category if specified
  const filtered = category
    ? scored.filter(s => s.doc.category === category)
    : scored;

  // Sort by relevance and take top results
  filtered.sort((a, b) => b.score - a.score);

  return filtered.slice(0, limit).map(s => ({
    id: s.doc.id,
    title: s.doc.title,
    category: s.doc.category,
    text: s.doc.text,
    relevance: Math.round(s.score * 100),
  }));
}

// ─── Build cache on startup ────────────────────────────────────────────────
buildTFIDF();
logger.info(`RAG engine initialized with ${REGULATORY_CORPUS.length} regulatory documents`);